def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity
        if item == 0:
            priorities[i] = 0
            continue
        if ratio == 0:
            priorities[i] = 0
            continue
        if 0 < ratio <= 1:
            score = 0
            for j in range(1, 8):
                sign = (-1) ** (j + 1)
                term = sign * (ratio ** j) / j
                score += term
            multiplier = 20 if ratio < 0.2 else 15 if ratio < 0.5 else 7 if ratio < 0.75 else 3
            priorities[i] = abs(score) * multiplier
            if ratio > 0.85:
                extra = 0
                for m in range(1, 5):
                    for n in range(1, 3):
                        extra += ((ratio ** (m + n)) / (m * n))
                priorities[i] += extra
            if ratio > 0.95:
                priorities[i] *= 0.8
        elif 1 < ratio <= 2:
            penalty = 0
            for k in range(1, 6):
                penalty += (ratio ** (2 * k)) / (k ** 2)
            priorities[i] = ratio ** 4 + penalty
            if ratio > 1.5:
                priorities[i] *= 1.1
            else:
                priorities[i] *= 0.9
        elif ratio > 2:
            penalty = 0
            for q in range(1, 4):
                inner_sum = 0
                for r in range(1, 5):
                    inner_sum += (ratio ** (q * r)) / (r * q)
                penalty += inner_sum / q
            priorities[i] = ratio ** 5 + penalty
            if ratio > 3:
                priorities[i] *= 1.25
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
    for i in range(len(priorities)):
        if 0 < priorities[i] < 1e-10:
            priorities[i] = 0
    return priorities
